//! MS-OI29500 audit tests: Style Resolution and Run Properties
//!
//! Tests from the Microsoft Office Implementation Notes (MS-OI29500) for
//! ISO 29500-1 §17.3.2 (run properties) and §17.7 (style resolution).
//!
//! These tests document behaviors where Microsoft Word deviates from or
//! supplements the ECMA-376/ISO 29500 standard.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{InlineNode, Mark};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/ms-styles-runs";

// -- helpers ----------------------------------------------------------------
fn text_nodes(p: &stemma::ParagraphNode) -> Vec<stemma::TextNode> {
    p.all_inlines_owned()
        .into_iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(*t),
            _ => None,
        })
        .collect()
}
// ── cs/rtl forces cs font slot (§17.3.2.26b) ──────────────────

/// MS-OI29500 §17.3.2.26 note b: When a run has w:cs or w:rtl, the cs
/// (or cstheme) font is used for ALL characters, regardless of Unicode range.
///
/// Our code stores font_family from ascii/hAnsi and font_cs separately,
/// but does not select font_cs when cs/rtl is present. The consumer sees
/// font_family="Arial" when it should see the cs font "David".
#[test]
fn ms_cs_forces_cs_font_for_latin_text() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cs-rtl-font-selection");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let cs_run = nodes
        .iter()
        .find(|n| n.text.contains("CS-forced"))
        .expect("should find CS-forced run");

    // When cs=true, the effective font should be the cs font (David), not ascii (Arial).
    // Currently we report font_family=Arial because we don't switch slots based on cs/rtl.
    assert_eq!(
        cs_run.style_props.font_family.as_deref(),
        Some("David"),
        "cs=true run should use cs font (David), not ascii font (Arial). \
         MS-OI29500 §17.3.2.26b: cs/rtl forces cs font slot."
    );
}

/// MS-OI29500 §17.3.2.26 note b: w:rtl also forces cs font slot.
#[test]
fn ms_rtl_forces_cs_font_for_latin_text() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cs-rtl-font-selection");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let rtl_run = nodes
        .iter()
        .find(|n| n.text.contains("RTL-forced"))
        .expect("should find RTL-forced run");

    assert_eq!(
        rtl_run.style_props.font_family.as_deref(),
        Some("David"),
        "rtl=true run should use cs font (David), not ascii font (Arial). \
         MS-OI29500 §17.3.2.26b: rtl forces cs font slot."
    );
}

/// Positive test: run without cs/rtl uses ascii font normally.
#[test]
fn ms_no_cs_uses_ascii_font() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cs-rtl-font-selection");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let normal_run = nodes
        .iter()
        .find(|n| n.text.contains("Normal Latin"))
        .expect("should find normal run");

    assert_eq!(
        normal_run.style_props.font_family.as_deref(),
        Some("Arial"),
        "run without cs/rtl should use ascii font (Arial)"
    );
}

// ── bCs/iCs/szCs for complex script runs (§17.3.2.2/17/39) ────

/// MS-OI29500 §17.3.2.2, §17.3.2.17, §17.3.2.39: When cs or rtl is set,
/// Word uses bCs instead of b, iCs instead of i, and szCs instead of sz.
///
#[test]
fn ms_cs_run_uses_bcs_ics_szcs() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cs-rtl-bold-italic-size");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let cs_run = nodes
        .iter()
        .find(|n| n.text.contains("CS run"))
        .expect("should find CS run");

    // CS run: b=off + bCs=on -> should display bold
    assert!(
        cs_run.marks.contains(&Mark::Bold),
        "cs=true run with b=off, bCs=on should be bold (from bCs). \
         We don't parse bCs."
    );

    // CS run: i=off + iCs=on -> should display italic
    assert!(
        cs_run.marks.contains(&Mark::Italic),
        "cs=true run with i=off, iCs=on should be italic (from iCs). \
         We don't parse iCs."
    );

    // CS run: sz=24 + szCs=28 -> should use szCs=28
    assert_eq!(
        cs_run.style_props.font_size,
        Some(28),
        "cs=true run with sz=24, szCs=28 should use szCs=28 for font size. \
         We don't parse szCs."
    );
}

/// Positive test: non-CS run uses b, i, sz (not their CS counterparts).
#[test]
fn ms_non_cs_run_uses_b_i_sz() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cs-rtl-bold-italic-size");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let non_cs_run = nodes
        .iter()
        .find(|n| n.text.contains("Non-CS run"))
        .expect("should find non-CS run");

    // Non-CS run: b=off -> not bold
    assert!(
        !non_cs_run.marks.contains(&Mark::Bold),
        "non-CS run with b val=0 should NOT be bold"
    );

    // Non-CS run: i=off -> not italic
    assert!(
        !non_cs_run.marks.contains(&Mark::Italic),
        "non-CS run with i val=0 should NOT be italic"
    );

    // Non-CS run: sz=24 -> size=24
    assert_eq!(
        non_cs_run.style_props.font_size,
        Some(24),
        "non-CS run with sz=24 should have font_size=24"
    );
}

// ── rFonts eastAsia="Times New Roman" special case (§17.3.2.26d) ──

/// MS-OI29500 §17.3.2.26 notes b,d: When eastAsia is "Times New Roman"
/// and ascii/hAnsi are equal, the ascii font is used even for East Asian
/// characters.
///
/// This is a font selection rule that our code does not implement. We store
/// font_east_asia as-is without applying the TNR override rule.
#[test]
fn ms_rfonts_eastasia_tnr_uses_ascii_font() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "rfonts-eastasia-tnr");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let tnr_run = nodes
        .iter()
        .find(|n| n.text.contains("TNR-eastAsia"))
        .expect("should find TNR-eastAsia run");

    // When eastAsia=TNR and ascii==hAnsi, the ascii font should be used
    // for East Asian content. We'd need a font_east_asia_effective or
    // similar mechanism to express this.
    //
    // For now, we just document that font_east_asia stores "Times New Roman"
    // but the effective font should be "Calibri" (the ascii font).
    assert_eq!(
        tnr_run.style_props.font_east_asia.as_deref(),
        Some("Calibri"),
        "When eastAsia='Times New Roman' and ascii==hAnsi, effective eastAsia \
         font should be the ascii font ('Calibri'). MS-OI29500 §17.3.2.26d."
    );
}

/// Positive test: normal eastAsia font is preserved.
#[test]
fn ms_rfonts_normal_eastasia_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "rfonts-eastasia-tnr");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let normal_run = nodes
        .iter()
        .find(|n| n.text.contains("Normal eastAsia"))
        .expect("should find normal eastAsia run");

    assert_eq!(
        normal_run.style_props.font_east_asia.as_deref(),
        Some("MS Mincho"),
        "eastAsia font should be MS Mincho when not Times New Roman"
    );
}

// ── rFonts hint attribute (§17.3.2.26b) ─────────────

/// MS-OI29500 §17.3.2.26 note b: The hint attribute influences font
/// selection for characters in ambiguous Unicode ranges. When hint=eastAsia,
/// characters in Latin-1 Supplement (like U+00B7 middle dot), Spacing
/// Modifier Letters, Greek, Cyrillic, etc. use the eastAsia font.
///
/// Previously our code did not parse the hint attribute and did not perform
/// per-character font selection. Now resolved.
#[test]
fn ms_rfonts_hint_eastasia_selects_ea_font() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "rfonts-hint-eastasia");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let hint_run = nodes
        .iter()
        .find(|n| n.text.contains("Hint eastAsia"))
        .expect("should find hint eastAsia run");

    // With hint=eastAsia, the effective font_family for characters in
    // Latin-1 Supplement should be the eastAsia font (MS Gothic), not
    // the hAnsi font (Arial). Our code always reports font_family=Arial
    // because we don't implement per-character font selection.
    assert_eq!(
        hint_run.style_props.font_family.as_deref(),
        Some("MS Gothic"),
        "hint=eastAsia run should use eastAsia font (MS Gothic) for Latin-1 \
         Supplement chars, not hAnsi font (Arial)."
    );
}

// ── rFonts theme cross-level override (§17.3.2.26e) ──

/// MS-OI29500 §17.3.2.26 note e: An ascii attribute at a higher style level
/// overrides an asciiTheme at a lower level. The override semantics apply
/// across the hierarchy, not just within a single rFonts element.
///
/// Previously overlay_marks treated font_family and font_family_theme as
/// independent channels. Now resolved: a child style setting ascii="Courier New"
/// correctly overrides the parent's asciiTheme.
#[test]
fn ms_rfonts_ascii_overrides_parent_ascii_theme() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "rfonts-theme-cross-level");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let run = &nodes[0];

    assert_eq!(
        run.style_props.font_family.as_deref(),
        Some("Courier New"),
        "Child style ascii='Courier New' should override parent's asciiTheme. \
         MS-OI29500 §17.3.2.26e."
    );
}

// ── Toggle properties in paragraph styles (§17.7.8) ───────────

/// MS-OI29500 §17.7.8: Word RESETS toggle properties in paragraph styles
/// rather than XORing them.
///
/// Setup: docDefaults bold=on. ParaStyle bold=on.
/// - Per ECMA spec (XOR): on ^ on = off
/// - Per Word (reset): bold = on
///
/// Our resolve_toggle_mark shortcuts to On when doc_default is On (line 714
/// of styles.rs), which happens to match Word's "reset" behavior here.
/// This is a pragmatic match — our code isn't implementing the full MS
/// "paragraph styles reset toggles" rule, but the shortcut produces the
/// same result for this common case.
#[test]
fn ms_toggle_para_style_resets_not_xors() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-para-style-reset");
    let paras = common::all_paragraphs(&doc);

    // Find the test paragraph (skip python-docx's default empty paragraphs)
    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Para style bold"))
        .expect("should find test paragraph");

    let nodes = text_nodes(p);
    let run = &nodes[0];

    // Word behavior: bold=on (reset, not XOR)
    // Our current behavior: bold=off (XOR of on ^ on = off)
    assert!(
        run.marks.contains(&Mark::Bold),
        "docDefaults bold=on + para style bold=on should produce bold=on (Word resets, not XORs). \
         MS-OI29500 §17.7.8."
    );
}

// ── Default font Times New Roman (§17.3.2.26c) ────────────────

/// MS-OI29500 §17.3.2.26 note c: When rFonts attributes are not specified
/// anywhere in the style chain, Word defaults all font slots to
/// "Times New Roman".
///
/// In practice, the python-docx template includes its own default fonts
/// (from the Normal style or docDefaults), so this test verifies the
/// specific MS-mandated default of TNR. Our code inherits whatever the
/// template provides rather than applying the MS-mandated default.
///
/// NOTE: The NoFontsPara style has no rFonts, but the document's docDefaults
/// provides asciiTheme="minorHAnsi" which resolves to "Cambria" through
/// the theme. So the style chain DOES provide a font. This test verifies
/// that fonts from docDefaults theme are resolved correctly.
///
/// The TNR fallback (tested below via unit test) only applies when the
/// ENTIRE resolution chain (including docDefaults and themes) yields no font.
#[test]
fn ms_default_font_is_times_new_roman() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "default-font-tnr");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Default font"))
        .expect("should find test paragraph");

    let nodes = text_nodes(p);
    let run = &nodes[0];

    // The fixture's docDefaults has asciiTheme="minorHAnsi" which resolves
    // to "Cambria" from the template theme. NoFontsPara has no rFonts,
    // so the resolved font comes from docDefaults.
    assert_eq!(
        run.style_props.font_family.as_deref(),
        Some("Cambria"),
        "NoFontsPara style gets font from docDefaults theme (minorHAnsi = Cambria)"
    );
}

// MS-OI29500 §17.3.2.26c: The TNR fallback is tested via a unit test in
// styles.rs (test name: `tnr_fallback_when_no_font_specified`), since
// the python-docx template always includes theme fonts in docDefaults.

// ── Special style IDs ignored (§17.7.4.17a) ──────────────────

/// MS-OI29500 §17.7.4.17 note a: Word ignores any child elements of style
/// definitions with styleId "NoList", "DefaultParagraphFont", or "TableNormal".
///
/// Our code processes all styles uniformly, including these special IDs.
/// If someone adds bold + color to DefaultParagraphFont, our resolver will
/// pick them up, but Word would ignore them.
#[test]
fn ms_special_style_ids_children_ignored() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "special-style-ids-ignored");
    let paras = common::all_paragraphs(&doc);

    let p = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("DefaultParagraphFont"))
        .expect("should find test paragraph");

    let nodes = text_nodes(p);
    let run = &nodes[0];

    // Bold and color were added to DefaultParagraphFont — Word ignores them.
    assert!(
        !run.marks.contains(&Mark::Bold),
        "DefaultParagraphFont's bold should be ignored. \
         MS-OI29500 §17.7.4.17a."
    );
    assert!(
        run.style_props.color.as_deref() != Some("FF0000"),
        "DefaultParagraphFont's color=FF0000 should be ignored. \
         MS-OI29500 §17.7.4.17a."
    );
}

// ── Linked style singly-linked (§17.7.4.6b) ───────────────────────────

/// MS-OI29500 §17.7.4.6 note b: Singly-linked style pairing is made
/// bidirectional by Word. If a paragraph style links to a character style
/// but the character style doesn't link back, Word treats it as bidirectional.
///
/// Positive test: the para style should provide its rPr to the paragraph.
#[test]
fn ms_linked_style_singly_para_gets_rpr() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "linked-style-singly");
    let paras = common::all_paragraphs(&doc);

    let p1 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Singly linked para"))
        .expect("should find singly linked para paragraph");

    let nodes = text_nodes(p1);
    let run = &nodes[0];

    assert!(
        run.marks.contains(&Mark::Bold),
        "LinkTestPara paragraph should be bold from para style rPr"
    );
    assert_eq!(
        run.style_props.font_size,
        Some(28),
        "LinkTestPara paragraph should have size=28 from para style rPr"
    );
}

/// The char style applied as rStyle should provide its own properties.
#[test]
fn ms_linked_style_singly_char_gets_rpr() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "linked-style-singly");
    let paras = common::all_paragraphs(&doc);

    let p2 = paras
        .iter()
        .find(|p| common::paragraph_text(p).contains("Singly linked char"))
        .expect("should find singly linked char paragraph");

    let nodes = text_nodes(p2);
    let run = nodes
        .iter()
        .find(|n| n.text.contains("Singly linked char"))
        .expect("should find char styled run");

    assert!(
        run.marks.contains(&Mark::Italic),
        "LinkTestChar run should be italic from char style rPr"
    );
    assert_eq!(
        run.style_props.color.as_deref(),
        Some("FF0000"),
        "LinkTestChar run should have color=FF0000 from char style rPr"
    );
}

// ── cstheme font resolution (§17.3.2.26) ──────────────────────────────

/// MS-OI29500 §17.3.2.26: cstheme=minorBidi should resolve the cs font
/// from the theme's minorFont cs typeface.
///
/// The fixture's theme has an empty cs typeface (`<a:cs typeface=""/>`), so
/// theme resolution yields an empty typeface; per MS-OI29500 §17.3.2.26c stemma
/// then falls back to "Times New Roman".
///
/// NOTE: the normative attribute is lowercase `w:cstheme` (the lone lowercase
/// theme attr in CT_Fonts; asciiTheme/hAnsiTheme/eastAsiaTheme are camelCase).
/// The fixture and reader both use the lowercase form; a camelCase `csTheme`
/// is non-normative and must not resolve.
#[test]
fn ms_rfonts_cs_theme_resolves_from_theme() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "rfonts-cs-theme");
    let paras = common::all_paragraphs(&doc);
    let nodes = text_nodes(paras[0]);

    let run = nodes
        .iter()
        .find(|n| n.text.contains("CS theme"))
        .expect("should find CS theme run");

    // csTheme=minorBidi resolves to an empty typeface in the default theme.
    // Per MS-OI29500 §17.3.2.26c, the fallback should be "Times New Roman".
    assert_eq!(
        run.style_props.font_cs.as_deref(),
        Some("Times New Roman"),
        "csTheme=minorBidi with empty theme typeface should fall back to \
         'Times New Roman' per MS-OI29500 §17.3.2.26c."
    );
}
